import React from "react";

/**
 * TechIcon
 * Accepts a tech name (string) or a URL, detects the technology,
 * and renders its SVG icon + label.
 * Automatically wraps the icon in an anchor tag linking to official docs.
 */

interface Props {
  name: string;
  showLabel?: boolean;
  size?: number;
}

