export default function TechIcon({ name, showLabel = true, size = 16 }: Props) {
  const tech = detect(name);
  const isUrl = name.startsWith("http");

  // Automatically fetch the destination URL if we successfully detected the technology
  const destinationHref = isUrl ? name : tech ? URLS[tech] : undefined;

  // Set up the shared base styling classes
  const baseClasses =
    "inline-flex items-center gap-1.5 text-[0.62rem] tracking-widest uppercase border px-2 py-0.5 transition-colors duration-200";

  // If a destination exists, we add hover classes so the user knows it is clickable
  const interactiveClasses = destinationHref
    ? "hover:border-ink hover:text-ink cursor-pointer"
    : "";

  if (!tech) {
    // Unknown tech — render as plain text pill (and link it if it's a URL)
    const content = isUrl ? new URL(name).hostname.replace("www.", "") : name;

    if (destinationHref) {
      return (
        <a
          href={destinationHref}
          target="_blank"
          rel="noopener noreferrer"
          className={`${baseClasses} ${interactiveClasses}`}
          style={{
            borderColor: "var(--color-border)",
            color: "var(--color-muted)",
          }}
        >
          {content}
        </a>
      );
    }

    return (
      <span
        className={baseClasses}
        style={{
          borderColor: "var(--color-border)",
          color: "var(--color-muted)",
        }}
      >
        {content}
      </span>
    );
  }

  const label = LABELS[tech];

  const content = (
    <>
      <svg
        role="img"
        viewBox="0 0 24 24"
        xmlns="http://www.w3.org/2000/svg"
        width={size}
        height={size}
        fill="currentColor"
        aria-hidden="true"
        focusable="false"
        style={{ flexShrink: 0 }}
      >
        {ICONS[tech]}
      </svg>
      {showLabel && label}
    </>
  );

  // If we have a mapped URL, render an anchor tag
  if (destinationHref) {
    return (
      <a
        href={destinationHref}
        target="_blank"
        rel="noopener noreferrer"
        className={`${baseClasses} ${interactiveClasses}`}
        style={{
          borderColor: "var(--color-border)",
          color: "var(--color-muted)",
        }}
        title={label}
      >
        {content}
      </a>
    );
  }

  // Fallback if no URL is mapped (e.g. if you remove something from the URLS dictionary)
  return (
    <span
      className={baseClasses}
      style={{
        borderColor: "var(--color-border)",
        color: "var(--color-muted)",
      }}
      title={label}
    >
      {content}
    </span>
  );
}
